<?php
// ALG3PL Scale Batch 2 — Deploy Script
// Writes PWA, Print/PDF, and Database Notification files
// Auto-deletes itself after execution
// Place in /public/ and hit it once via browser or curl

$base = realpath(dirname(__FILE__) . '/..');
$errors = [];
$success = [];

function writeFile($path, $b64Content, &$success, &$errors) {
    $dir = dirname($path);
    if (!is_dir($dir) && !mkdir($dir, 0755, true)) {
        $errors[] = 'Could not create dir: ' . $dir;
        return;
    }
    $content = base64_decode($b64Content);
    if (file_put_contents($path, $content) !== false) {
        $success[] = 'Written: ' . str_replace($GLOBALS['base'], '', $path) . ' (' . strlen($content) . ' bytes)';
    } else {
        $errors[] = 'FAILED to write: ' . $path;
    }
}

writeFile($base . '/public/manifest.json', '', $success, $errors);
writeFile($base . '/public/sw.js', '', $success, $errors);
writeFile($base . '/app/Providers/Filament/AdminPanelProvider.php', '', $success, $errors);
writeFile($base . '/app/Filament/Resources/CountryReportResource.php', '', $success, $errors);
writeFile($base . '/routes/web.php', '', $success, $errors);
writeFile($base . '/app/Http/Controllers/PrintController.php', '', $success, $errors);
writeFile($base . '/app/Observers/LeadObserver.php', '', $success, $errors);
writeFile($base . '/app/Notifications/NewLeadAssigned.php', '', $success, $errors);
writeFile($base . '/app/Notifications/TaskOverdue.php', '', $success, $errors);
writeFile($base . '/resources/views/filament/print/country-report.blade.php', '', $success, $errors);

// Notifications table migration
$migrationContent = base64_decode('');
$migrationPath = $base . '/database/migrations/2024_01_01_000000_create_notifications_table.php';
if (!file_exists($migrationPath)) {
    if (file_put_contents($migrationPath, $migrationContent) !== false) {
        $success[] = 'Written: notifications migration';
    } else {
        $errors[] = 'FAILED to write notifications migration';
    }
} else {
    $success[] = 'Skipped: notifications migration already exists';
}

// Run artisan commands if exec() is available
if (function_exists('exec')) {
    $artisan = $base . '/artisan';
    if (file_exists($artisan)) {
        exec('php ' . escapeshellarg($artisan) . ' migrate --force 2>&1', $out, $ret);
        $success[] = 'migrate --force: exit=' . $ret . ' | ' . trim(implode(' ', array_slice($out, -3)));
        exec('php ' . escapeshellarg($artisan) . ' route:clear 2>&1', $out2, $ret2);
        $success[] = 'route:clear: exit=' . $ret2;
        exec('php ' . escapeshellarg($artisan) . ' config:clear 2>&1', $out3, $ret3);
        $success[] = 'config:clear: exit=' . $ret3;
        exec('php ' . escapeshellarg($artisan) . ' view:clear 2>&1', $out4, $ret4);
        $success[] = 'view:clear: exit=' . $ret4;
    } else {
        $errors[] = 'artisan not found at: ' . $artisan;
    }
} else {
    $errors[] = 'exec() not available — run php artisan migrate --force manually';
}

// Output
header('Content-Type: text/plain; charset=utf-8');
echo '=== ALG3PL Scale Batch 2 Deploy ===' . PHP_EOL;
echo 'Time: ' . date('Y-m-d H:i:s') . PHP_EOL . PHP_EOL;
echo '--- SUCCESS (' . count($success) . ') ---' . PHP_EOL;
foreach ($success as $msg) { echo '  [OK] ' . $msg . PHP_EOL; }
if ($errors) {
    echo PHP_EOL . '--- ERRORS (' . count($errors) . ') ---' . PHP_EOL;
    foreach ($errors as $msg) { echo '  [ERR] ' . $msg . PHP_EOL; }
}
echo PHP_EOL . '=== DONE ===' . PHP_EOL;

unlink(__FILE__);
echo 'Deploy script self-deleted.' . PHP_EOL;